--
-- Table structure for table `incoming_transmittal_detail`
--

DROP TABLE IF EXISTS `incoming_transmittal_detail`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `incoming_transmittal_detail` (
  `incoming_transmittal_detail_id` bigint(20) NOT NULL AUTO_INCREMENT,
  `document_id` bigint(20) DEFAULT 0,
  `document_url` text DEFAULT NULL,
  `document_file` text DEFAULT NULL,
  `document_file_revision` text DEFAULT NULL,
  `document_crs` text DEFAULT NULL,
  `incoming_transmittal_id` bigint(20) DEFAULT 0,
  `project_id` bigint(20) DEFAULT 0,
  `vendor_id` bigint(20) DEFAULT 0,
  `remark` text DEFAULT NULL,
  `issue_status_incoming_id` bigint(20) DEFAULT 0,
  `issue_status_id` bigint(20) DEFAULT 0,
  `return_status_id` bigint(20) DEFAULT 0,
  `document_status_id` bigint(20) DEFAULT 0,
  PRIMARY KEY (`incoming_transmittal_detail_id`),
  KEY `IX_DOC` (`document_id`),
  KEY `IX_PROJECT` (`project_id`),
  KEY `IX_VENDOR` (`vendor_id`),
  KEY `IX_TRANS` (`incoming_transmittal_id`),
  KEY `IX_ISSUE` (`issue_status_incoming_id`),
  KEY `IX_STATUS_ID` (`issue_status_id`),
  KEY `IX_RETURN` (`return_status_id`)
) ENGINE=InnoDB AUTO_INCREMENT=373 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

