CREATE DEFINER=`edmg_user`@`localhost` PROCEDURE `sp_current_vdrl`()
BEGIN
		DROP  TEMPORARY TABLE IF EXISTS temp_user_reviewer;
		DROP  TEMPORARY TABLE IF EXISTS temp_user_approver;
		DROP  TEMPORARY TABLE IF EXISTS temp_user_observer;
		DROP  TEMPORARY TABLE IF EXISTS temp_current_vdrl;
		CREATE TEMPORARY TABLE temp_user_reviewer AS (
			SELECT 	assignment.assignment_id, assignment.incoming_transmittal_detail_id, comment.role, GROUP_CONCAT(comment.user_id) AS user_id
			FROM 	assignment LEFT JOIN db_edms.comment ON assignment.assignment_id = comment.assignment_id
			WHERE 	comment.role = 'REVIEWER'
			GROUP BY assignment.assignment_id, assignment.incoming_transmittal_detail_id, comment.role
		);
		CREATE TEMPORARY TABLE temp_user_observer AS (
			SELECT 	assignment.assignment_id, assignment.incoming_transmittal_detail_id, comment.role, GROUP_CONCAT(comment.user_id) AS user_id
			FROM 	assignment LEFT JOIN db_edms.comment ON assignment.assignment_id = comment.assignment_id
			WHERE 	comment.role = 'OBSERVER'
			GROUP BY assignment.assignment_id, assignment.incoming_transmittal_detail_id, comment.role
		);
		CREATE TEMPORARY TABLE temp_user_approver AS (
			SELECT 	assignment.assignment_id, assignment.incoming_transmittal_detail_id, comment.role, GROUP_CONCAT(comment.user_id) AS user_id
			FROM 	assignment LEFT JOIN db_edms.comment ON assignment.assignment_id = comment.assignment_id
			WHERE 	comment.role = 'APPROVER'
			GROUP BY assignment.assignment_id, assignment.incoming_transmittal_detail_id, comment.role
		);
		CREATE TEMPORARY TABLE temp_current_vdrl AS (
			SELECT	document.document_no, document.document_title, document.document_description
				, document.ref_no, document.incoming_transmittal_detail_id
				, temp_user_reviewer.user_id AS reviewer
				, temp_user_approver.user_id AS approver
				, temp_user_observer.user_id AS observer
			FROM 	document LEFT JOIN assignment ON (document.incoming_transmittal_detail_id = assignment.incoming_transmittal_detail_id AND document.document_id = assignment.document_id)
			LEFT JOIN temp_user_reviewer ON assignment.assignment_id = temp_user_reviewer.assignment_id
			LEFT JOIN temp_user_approver ON assignment.assignment_id = temp_user_approver.assignment_id
			LEFT JOIN temp_user_observer ON assignment.assignment_id = temp_user_observer.assignment_id
			
			WHERE 	document.status NOT IN (0,88)
		);
		
	END ;;
