CREATE DEFINER=`edmg_user`@`localhost` PROCEDURE `sp_list_comment_idc`()
BEGIN
		DROP  TEMPORARY TABLE IF EXISTS temp_current_reviewer;
		DROP  TEMPORARY TABLE IF EXISTS temp_list_reviewer;
		CREATE TEMPORARY TABLE temp_current_reviewer AS (
			SELECT 	comment.assignment_id, MIN(comment.order_no) AS nomor
			FROM 	`comment` INNER JOIN assignment ON comment.assignment_id = assignment.assignment_id
			INNER JOIN document ON assignment.document_id = document.document_id
			INNER JOIN incoming_transmittal_detail ON assignment.incoming_transmittal_detail_id = incoming_transmittal_detail.incoming_transmittal_detail_id
			INNER JOIN incoming_transmittal ON incoming_transmittal_detail.incoming_transmittal_id = incoming_transmittal.incoming_transmittal_id
			WHERE 	comment.status = 1 AND document.status = 2 AND comment.status_nonaktif != 1 AND incoming_transmittal.status != 3 AND comment.role != 'OBSERVER'
			GROUP BY comment.assignment_id
		);
		CREATE TEMPORARY TABLE temp_list_reviewer AS (
			SELECT 	comment.*, project.project_name, document.document_no, document.document_title, document.document_type_id
				, ref_document_type.name AS document_type_name, document.vendor_id, document.area_id, ref_vendor.name AS vendor_name, ref_issue_status.name AS issue_status
			FROM 	`comment` INNER JOIN assignment ON comment.assignment_id = assignment.assignment_id
			INNER JOIN temp_current_reviewer ON (comment.assignment_id = temp_current_reviewer.assignment_id AND comment.order_no = temp_current_reviewer.nomor)
			INNER JOIN document ON assignment.document_id = document.document_id
			LEFT JOIN incoming_transmittal_detail ON assignment.incoming_transmittal_detail_id = incoming_transmittal_detail.incoming_transmittal_detail_id
			LEFT JOIN incoming_transmittal ON incoming_transmittal_detail.incoming_transmittal_id = incoming_transmittal.incoming_transmittal_id
			LEFT JOIN ref_document_type ON document.document_type_id = ref_document_type.document_type_id
			LEFT JOIN ref_vendor ON document.vendor_id = ref_vendor.vendor_id
			LEFT JOIN project ON document.project_id = project.project_id
			LEFT JOIN ref_area ON document.area_id = ref_area.area_id
			LEFT JOIN ref_issue_status ON document.issue_status_id = ref_issue_status.issue_status_id
			WHERE 	comment.status = 1 AND document.status = 2 AND comment.status_nonaktif != 1 AND incoming_transmittal.status != 3 AND comment.role != 'OBSERVER'
		);
	END ;;
DELIMITER ;
